VALUES
  ('judicial-57112235-moex-00587', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關我國監獄舍房騷動事故之相關敘述，下列何者錯誤？', '["舍房騷動，俗稱為「鬧房」或「搖房」", "一般係由少數受刑人帶頭起鬨，叫囂其他受刑人，公然對抗監獄管理階層的群眾行為", "舍房騷動是戒護安全不穩定的象徵", "舍房騷動一般不易演變成暴動，不用積極處理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00588', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '福克斯（Fox）與史丁克孔（Stinchcomb）於1999年提出暴動發生階段論，有關其主張之暴動發 生排序的敘述，下列何者正確？', '["最初爆發階段、組織階段、對抗階段、結束階段、說明階段", "最初爆發階段、對抗階段、組織階段、結束階段、說明階段", "最初爆發階段、組織階段、對抗階段、說明階段、結束階段", "最初爆發階段、對抗階段、組織階段、說明階段、結束階段"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00589', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關我國監獄行刑法制之發展，下列敘述何者錯誤？', '["清光緒31年（1905）聘請日人小河滋次郎博士起草「監獄律草案」凡240條，並立即實施", "北京政府時期，根據小河氏之草案，陸續制訂諸如「監獄規則」等各種監獄法規，惟民國15年， 由於革命軍興，遂一時受阻", "國民政府實行五權分立制度，為使監獄行刑法制化，於民國17年公布「監獄規則」，但因抗戰軍興， 未能全面實施", "國民政府於民國35年1月19日重新制定「監獄行刑法」，共98條，於民國36年6月10日施行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00590', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法之意義與功能，下列敘述何者錯誤？', '["監獄行刑概念係指狹義的徒刑、拘役、易服勞役之執行，亦涵蓋廣義的生命刑、財產刑", "監獄行刑概念係指狹義的徒刑之執行，主要功能係對受刑人應報懲罰", "監獄行刑法的功能在於確保受刑人權益，促使受刑人再社會化，防制社會上潛在的犯罪人", "監獄行刑法係規定國家具體執行刑事刑罰所應遵循之法律與規範"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00591', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法第12條規定，入監或在監婦女請求攜帶未滿3歲之子女應先經評估者，監獄應通知何 處之直轄市、縣（市）社會福利主管機關進行評估？', '["子女戶籍所在地", "判決法院所在地", "監獄所在地", "指揮執行檢察署所在地"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00592', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法第26條規定，下列何者不屬於「得由受刑人分任災害防救工作」必要條件之一？', '["遇有天災", "遇有受刑人受傷時", "遇有事變", "為防護監獄設施及受刑人安全時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00593', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人不服監獄所為影響其個人權益之處分或管理措施之申訴，應自受刑人收受或知悉處分或管理措 施之次日起，一定期間內為之，依監獄行刑法規定，下列敘述何者正確？', '["10日不變期間內", "15日不變期間內", "20日不變期間內", "25日不變期間內"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00594', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人執行刑期期滿者之釋放，依監獄行刑法規定，下列敘述何者正確？', '["應於其刑期終了之翌日午前釋放之", "應於其刑期終了之當日午前釋放之", "應於其刑期終了之當日午後釋放之", "應於其刑期終了之當日24小時內釋放之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00595', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法第5條規定，監獄對收容之受刑人，應按下列何者嚴為分界？', '["性別", "刑期", "犯次", "國籍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00596', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法第58條規定，下列何者得於監獄病舍或附設之病監收容之？', '["處拘役及罰金易服勞役之受刑人", "須加強教化之受刑人", "不宜與其他受刑人群居之和緩處遇受刑人", "罹患疾病經醫師評估認需密切觀察及處置之受刑人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
